INSERT INTO products (id, name, slug, category, short_description, long_description, price_display, price_value, image, images, tags, featured, in_stock, line_inquiry_text, strain, thc_content, weight, effects, sort_order) VALUES
  ('cajan-mintz', 'Cajan Mintz', 'cajan-mintz', 'flower', 'Minty hybrid — cool menthol finish, heavy hitter', 'Cajan Mintz delivers a unique minty terpene profile with a powerful THC punch. Dense, frosty nugs with a cool menthol exhale and deep body relaxation.', '฿200 / 1g', 200, '/images/products/strains/cajan-mintz.jpeg', ARRAY['/images/products/strains/cajan-mintz.jpeg', '/images/products/strains/cajan-mintz-alt.jpeg'], ARRAY['hybrid', 'minty', 'potent', 'indoor'], true, true, 'Hi! I''d like to order Cajan Mintz.', 'hybrid', 'High', '1g / 10g', ARRAY['Relaxed', 'Euphoric', 'Tingly', 'Happy'], 1),
  ('code-red', 'Code Red', 'code-red', 'flower', 'Indica-leaning — deep red hairs, knockout potency', 'Code Red is a heavy-hitting indica-leaning hybrid covered in fiery red pistils. Expect a full-body melt with earthy berry undertones.', '฿200 / 1g', 200, '/images/products/strains/code-red.jpeg', ARRAY['/images/products/strains/code-red.jpeg', '/images/products/strains/code-red-alt.jpeg'], ARRAY['indica', 'potent', 'berry', 'indoor'], true, true, 'Hi! I''d like to order Code Red.', 'indica', 'Very High', '1g / 10g', ARRAY['Sleepy', 'Relaxed', 'Hungry', 'Euphoric'], 2),
  ('miami-vice', 'Miami Vice', 'miami-vice', 'flower', 'Sativa-dominant — tropical, fruity, uplifting high', 'Miami Vice brings the sunshine with bright tropical flavours and an energising cerebral high. Perfect for social sessions and creative flow.', '฿200 / 1g', 200, '/images/products/strains/miami-vice.jpeg', ARRAY['/images/products/strains/miami-vice.jpeg', '/images/products/strains/miami-vice-alt.jpeg'], ARRAY['sativa', 'tropical', 'fruity', 'uplifting'], true, true, 'Hi! I''d like to order Miami Vice.', 'sativa', 'High', '1g / 10g', ARRAY['Euphoric', 'Energetic', 'Creative', 'Happy'], 3),
  ('top-banana-fritter', 'Top Banana Fritter', 'top-banana-fritter', 'flower', 'Hybrid — creamy banana dessert terps, balanced high', 'Top Banana Fritter is a premium dessert strain with rich banana-cream flavour. Perfectly balanced between head and body for an all-day smoke.', '฿200 / 1g', 200, '/images/products/strains/top-banana-fritter.jpeg', ARRAY['/images/products/strains/top-banana-fritter.jpeg', '/images/products/strains/top-banana-fritter-alt.jpeg'], ARRAY['hybrid', 'dessert', 'banana', 'top-shelf'], true, true, 'Hi! I''d like to order Top Banana Fritter.', 'hybrid', 'High', '1g / 10g', ARRAY['Happy', 'Relaxed', 'Creative', 'Euphoric'], 4),
  ('dosidos', 'Do-Si-Dos', 'dosidos', 'flower', 'Indica — lime & mint cookies, deep relaxation', 'Do-Si-Dos is a potent indica with OGKB x GSC genetics. Expect earthy lime and mint cookie flavours with a powerful sedative body high.', '฿180 / 1g', 180, '/images/products/strains/dosidos.jpeg', '{}', ARRAY['indica', 'cookies', 'potent', 'indoor'], false, true, 'Hi! I''d like to order Do-Si-Dos.', 'indica', 'Very High', '1g / 10g', ARRAY['Sleepy', 'Relaxed', 'Euphoric', 'Body High'], 5),
  ('double-up', 'Double Up', 'double-up', 'flower', 'Hybrid — double the terps, double the vibes', 'Double Up is a flavour-packed hybrid with a complex terpene profile. Smooth smoke with a balanced, mood-lifting effect.', '฿180 / 1g', 180, '/images/products/strains/double-up.jpeg', '{}', ARRAY['hybrid', 'smooth', 'balanced', 'indoor'], false, true, 'Hi! I''d like to order Double Up.', 'hybrid', 'High', '1g / 10g', ARRAY['Creative', 'Happy', 'Relaxed', 'Social'], 6),
  ('granpa-cookies', 'Grandpa Cookies', 'granpa-cookies', 'flower', 'Indica — classic cookie genetics, couch-lock vibes', 'Grandpa Cookies brings old-school cookie genetics with a modern twist. Dense, resinous buds with sweet dough flavour and heavy indica effects.', '฿180 / 1g', 180, '/images/products/strains/granpa-cookies.jpeg', '{}', ARRAY['indica', 'cookies', 'classic', 'indoor'], false, true, 'Hi! I''d like to order Grandpa Cookies.', 'indica', 'High', '1g / 10g', ARRAY['Sleepy', 'Hungry', 'Relaxed', 'Cozy'], 7),
  ('guava-bomba', 'Guava Bomba', 'guava-bomba', 'flower', 'Sativa — tropical guava explosion, uplifting', 'Guava Bomba bursts with sweet tropical guava terps. A sativa-leaning strain perfect for daytime with energising and creative effects.', '฿180 / 1g', 180, '/images/products/strains/guava-bomba.jpeg', '{}', ARRAY['sativa', 'tropical', 'fruity', 'daytime'], false, true, 'Hi! I''d like to order Guava Bomba.', 'sativa', 'Medium-High', '1g / 10g', ARRAY['Energetic', 'Creative', 'Happy', 'Focused'], 8),
  ('pineapple-gelato', 'Pineapple Gelato', 'pineapple-gelato', 'flower', 'Hybrid — sweet pineapple gelato, smooth & potent', 'Pineapple Gelato combines Gelato genetics with tropical pineapple terps. Creamy smooth smoke with a balanced euphoric high.', '฿180 / 1g', 180, '/images/products/strains/pineapple-gelato.jpeg', '{}', ARRAY['hybrid', 'gelato', 'tropical', 'smooth'], false, true, 'Hi! I''d like to order Pineapple Gelato.', 'hybrid', 'High', '1g / 10g', ARRAY['Euphoric', 'Happy', 'Relaxed', 'Creative'], 9),
  ('purple-gas-mask', 'Purple Gas Mask', 'purple-gas-mask', 'flower', 'Indica — deep purple, gassy nose, knockout punch', 'Purple Gas Mask is a visually stunning indica with deep purple colouring and a pungent gas aroma. Heavy-hitting for experienced smokers.', '฿200 / 1g', 200, '/images/products/strains/purple-gas-mask.jpeg', '{}', ARRAY['indica', 'premium', 'gassy', 'purple'], false, true, 'Hi! I''d like to order Purple Gas Mask.', 'indica', 'Very High', '1g / 10g', ARRAY['Sleepy', 'Relaxed', 'Euphoric', 'Pain Relief'], 10),
  ('subzero-cherry', 'Subzero Cherry', 'subzero-cherry', 'flower', 'Hybrid — icy cherry terps, frosty trichomes', 'Subzero Cherry is dripping with trichomes and bursting with sweet cherry flavour. A balanced hybrid for any occasion.', '฿180 / 1g', 180, '/images/products/strains/subzero-cherry.jpeg', '{}', ARRAY['hybrid', 'fruity', 'cherry', 'frosty'], false, true, 'Hi! I''d like to order Subzero Cherry.', 'hybrid', 'High', '1g / 10g', ARRAY['Happy', 'Euphoric', 'Relaxed', 'Uplifting'], 11),
  ('supreme-oreoz', 'Supreme Oreoz', 'supreme-oreoz', 'flower', 'Indica — cookies & cream flavour, heavy hitter', 'Supreme Oreoz is a dessert lover''s dream with rich chocolate and cream terps. Dense indica buds that deliver deep body relaxation.', '฿200 / 1g', 200, '/images/products/strains/supreme-oreoz.jpeg', '{}', ARRAY['indica', 'dessert', 'premium', 'indoor'], false, true, 'Hi! I''d like to order Supreme Oreoz.', 'indica', 'Very High', '1g / 10g', ARRAY['Sleepy', 'Relaxed', 'Hungry', 'Euphoric'], 12),
  ('west-coast-diesel', 'West Coast Diesel', 'west-coast-diesel', 'flower', 'Sativa — diesel fuel nose, energising cerebral high', 'West Coast Diesel is a classic sativa with sharp diesel aromatics and an electric cerebral buzz. Ideal for wake-and-bake sessions.', '฿180 / 1g', 180, '/images/products/strains/west-coast-diesel.jpeg', '{}', ARRAY['sativa', 'diesel', 'classic', 'energising'], false, true, 'Hi! I''d like to order West Coast Diesel.', 'sativa', 'High', '1g / 10g', ARRAY['Energetic', 'Focused', 'Creative', 'Uplifting'], 13),
  ('top-snow-ball', 'Top Snow Ball', 'top-snow-ball', 'flower', 'Indoor Sativa 100% — frosty, potent, premium', 'Top Snow Ball is a premium indoor-grown Sativa strain known for its dense, crystal-coated buds and uplifting cerebral effects.', '฿200 / 1g', 200, '/images/products/top-snow-ball.jpg', '{}', ARRAY['sativa', 'indoor', 'premium', 'top-shelf'], false, true, 'Hi! I''d like to order Top Snow Ball.', 'sativa', 'High', '1g / 10g', ARRAY['Euphoric', 'Creative', 'Energetic', 'Uplifting'], 14),
  ('top-papaya-fiya', 'Top Papaya Fiya', 'top-papaya-fiya', 'flower', 'Indoor hybrid — tropical flavour, smooth high', 'Top Papaya Fiya is a flavourful indoor hybrid with tropical papaya notes and a beautifully balanced high. Perfect for any time of day.', '฿80 / 1g', 80, '/images/products/top-papaya-fiya.jpg', '{}', ARRAY['hybrid', 'indoor', 'tropical', 'smooth'], false, true, 'Hi! I''d like to order Top Papaya Fiya.', 'hybrid', 'Medium-High', '1g / 10g', ARRAY['Relaxed', 'Happy', 'Creative', 'Chill'], 15),
  ('og-kush-premium', 'OG Kush Premium', 'og-kush-premium', 'flower', 'Classic indica-dominant — earthy, piney, potent', 'A legendary strain with deep earthy and pine aromas. Our OG Kush Premium delivers heavy relaxation with a euphoric mental buzz.', '฿150 / 1g', 150, '/images/products/og-kush.jpg', '{}', ARRAY['indica', 'classic', 'potent', 'earthy'], false, true, 'Hi! I''d like to order OG Kush Premium.', 'indica', 'High', '1g / 10g', ARRAY['Relaxed', 'Euphoric', 'Sleepy', 'Hungry'], 16),
  ('mango-haze', 'Mango Haze', 'mango-haze', 'flower', 'Sativa-dominant — sweet mango aroma, uplifting', 'Mango Haze brings tropical sweetness with a clear-headed, energising sativa effect. Great for daytime use and creative sessions.', '฿120 / 1g', 120, '/images/products/mango-haze.jpg', '{}', ARRAY['sativa', 'tropical', 'daytime', 'sweet'], false, true, 'Hi! I''d like to order Mango Haze.', 'sativa', 'Medium', '1g / 10g', ARRAY['Energetic', 'Happy', 'Creative', 'Focused'], 17);
