  ('kanha-watermelon-hybrid', 'KANHA Watermelon Hybrid', 'kanha-watermelon-hybrid', 'edible', 'Hybrid gummy — juicy watermelon, balanced effects', 'KANHA Watermelon Hybrid gummies combine sweet watermelon flavour with perfectly balanced hybrid effects. Great for first-timers and experienced users alike.', '฿165', 165, '/images/products/edibles/kanha-watermelon-hybrid.jpeg', ARRAY['/images/products/edibles/kanha-watermelon-hybrid.jpeg', '/images/products/edibles/kanha-watermelon-details.jpeg'], ARRAY['edible', 'gummy', 'watermelon', 'hybrid'], true, true, 'Hi! I''d like to order KANHA Watermelon Hybrid.', 'KANHA', ARRAY['Balanced', 'Relaxed', 'Happy', 'Chill'], '[{"label": "1 pack", "price": 165}]', 19),
  ('kanha-tranquility-blueberry', 'KANHA Tranquility Blueberry', 'kanha-tranquility-blueberry', 'edible', 'CBD+THC gummy — blueberry calm, sleep aid', 'KANHA Tranquility Blueberry gummies blend CBD and THC for serene relaxation. Sweet blueberry flavour with calming effects perfect for winding down.', '฿165', 165, '/images/products/edibles/kanha-tranquility-blueberry.jpeg', ARRAY['/images/products/edibles/kanha-tranquility-blueberry.jpeg', '/images/products/edibles/kanha-tranquility-details.jpeg'], ARRAY['edible', 'gummy', 'blueberry', 'cbd', 'sleep'], false, true, 'Hi! I''d like to order KANHA Tranquility Blueberry.', 'KANHA', ARRAY['Calm', 'Sleepy', 'Relaxed', 'Peaceful'], '[{"label": "1 pack", "price": 165}]', 20),
  ('kanha-love-raspberry', 'KANHA Love Raspberry', 'kanha-love-raspberry', 'edible', 'Aphrodisiac gummy — raspberry love, feel-good vibes', 'KANHA Love Raspberry gummies are infused with mood-enhancing botanicals and sweet raspberry flavour for a feel-good social experience.', '฿165', 165, '/images/products/edibles/kanha-love-raspberry.jpeg', ARRAY['/images/products/edibles/kanha-love-raspberry.jpeg', '/images/products/edibles/kanha-love-raspberry-details.jpeg'], ARRAY['edible', 'gummy', 'raspberry', 'love', 'social'], false, true, 'Hi! I''d like to order KANHA Love Raspberry.', 'KANHA', ARRAY['Happy', 'Social', 'Euphoric', 'Giggly'], '[{"label": "1 pack", "price": 165}]', 21),
  ('kanha-love-fx-damiana', 'KANHA Love FX Damiana', 'kanha-love-fx-damiana', 'edible', 'FX gummy — damiana-infused, romantic vibes', 'KANHA Love FX Damiana gummies feature damiana leaf extract for an elevated romantic experience, paired with delicious flavour.', '฿165', 165, '/images/products/edibles/kanha-love-details.jpeg', ARRAY['/images/products/edibles/kanha-love-details.jpeg', '/images/products/edibles/kanha-love-raspberry.jpeg'], ARRAY['edible', 'gummy', 'fx', 'damiana', 'love'], false, true, 'Hi! I''d like to order KANHA Love FX Damiana.', 'KANHA', ARRAY['Romantic', 'Happy', 'Euphoric', 'Social'], '[{"label": "1 pack", "price": 165}]', 22),
  ('kanha-harmony-acai', 'KANHA Harmony Açaí', 'kanha-harmony-acai', 'edible', 'Balanced gummy — açaí berry, 1:1 CBD:THC harmony', 'KANHA Harmony Açaí gummies offer a perfect 1:1 CBD:THC ratio with delicious açaí berry flavour. Ideal for gentle, balanced effects.', '฿165', 165, '/images/products/edibles/kanha-harmony-acai.jpeg', '{}', ARRAY['edible', 'gummy', 'acai', 'balanced', 'cbd'], false, true, 'Hi! I''d like to order KANHA Harmony Açaí.', 'KANHA', ARRAY['Balanced', 'Calm', 'Happy', 'Gentle'], '[{"label": "1 pack", "price": 165}]', 23),
  ('kanha-cbd-tangerine', 'KANHA CBD Tangerine', 'kanha-cbd-tangerine', 'edible', 'Pure CBD gummy — tangerine citrus, zero high', 'KANHA CBD Tangerine gummies provide pure CBD benefits with bright tangerine flavour. Zero psychoactive effects — perfect for wellness seekers.', '฿165', 165, '/images/products/edibles/kanha-cbd-tangerine.jpeg', '{}', ARRAY['edible', 'gummy', 'cbd', 'tangerine', 'wellness'], false, true, 'Hi! I''d like to order KANHA CBD Tangerine.', 'KANHA', ARRAY['Calm', 'Focused', 'Relaxed', 'No High'], '[{"label": "1 pack", "price": 165}]', 24),
  ('kanha-passionfruit', 'KANHA Passionfruit', 'kanha-passionfruit', 'edible', 'Sativa gummy — tropical passionfruit, uplifting', 'KANHA Passionfruit gummies pack sweet tropical passionfruit flavour with energising sativa effects. Perfect for daytime enjoyment.', '฿165', 165, '/images/products/edibles/kanha-passionfruit.jpeg', '{}', ARRAY['edible', 'gummy', 'passionfruit', 'sativa', 'tropical'], false, true, 'Hi! I''d like to order KANHA Passionfruit.', 'KANHA', ARRAY['Energetic', 'Happy', 'Creative', 'Uplifting'], '[{"label": "1 pack", "price": 165}]', 25),
  ('kanha-tangerine-twist', 'KANHA Tangerine Twist', 'kanha-tangerine-twist', 'edible', 'Indica gummy — tangerine twist, mellow nightcap', 'KANHA Tangerine Twist gummies combine zesty tangerine with indica effects for a mellow, relaxing nightcap experience.', '฿165', 165, '/images/products/edibles/kanha-tangerine-twist.jpeg', '{}', ARRAY['edible', 'gummy', 'tangerine', 'indica', 'evening'], false, true, 'Hi! I''d like to order KANHA Tangerine Twist.', 'KANHA', ARRAY['Relaxed', 'Sleepy', 'Calm', 'Mellow'], '[{"label": "1 pack", "price": 165}]', 26),
  ('kanha-cranpomegranate', 'KANHA Cran-Pomegranate', 'kanha-cranpomegranate', 'edible', 'THC gummy — tart cran-pomegranate, great taste', 'KANHA Cran-Pomegranate gummies deliver a delicious tart berry flavour with consistent THC dosing for a reliable, enjoyable experience.', '฿165', 165, '/images/products/edibles/kanha-cranpomegranate.jpeg', '{}', ARRAY['edible', 'gummy', 'cranberry', 'pomegranate', 'thc'], false, true, 'Hi! I''d like to order KANHA Cran-Pomegranate.', 'KANHA', ARRAY['Happy', 'Relaxed', 'Euphoric', 'Giggly'], '[{"label": "1 pack", "price": 165}]', 27),
  ('kanha-belts-runtz', 'KANHA Belts Runtz', 'kanha-belts-runtz', 'edible', 'Gummy belt — Runtz flavour, fun & potent', 'KANHA Belts Runtz are fun, chewy gummy belts with the iconic Runtz candy flavour. A tasty, potent alternative to traditional gummies.', '฿165', 165, '/images/products/edibles/kanha-belts-runtz.jpeg', '{}', ARRAY['edible', 'belt', 'runtz', 'candy', 'fun'], false, true, 'Hi! I''d like to order KANHA Belts Runtz.', 'KANHA', ARRAY['Happy', 'Giggly', 'Relaxed', 'Fun'], '[{"label": "1 pack", "price": 165}]', 28);
