  ('acrylic-bong-unbreakable', 'บ้องอะคริลิก ตกไม่แตก', 'acrylic-bong-unbreakable', 'accessory', 'บ้องอะคริลิก 30cm ตกไม่แตก พกพาง่าย หมุนถอดล้างได้', 'บ้องตกไม่แตก 💯 พัสดุอะคริลิก ขนาด 30cm มีอุปกรณ์ล้างบ้องให้ครบจบ สะดวกสำหรับคนที่เดินทางและทำอุปกรณ์บ้องตกบ่อย พกพาง่ายสะดวก หมุนถอดล้างได้', '฿990 / กล่อง', 990, '/images/products/bongs/acrylic-bong.jpeg', ARRAY['/images/products/bongs/acrylic-bong.jpeg', '/images/products/bongs/acrylic-bong-1.jpeg', '/images/products/bongs/acrylic-bong-2.jpeg', '/images/products/bongs/acrylic-bong-3.jpeg'], ARRAY['bong', 'acrylic', 'unbreakable', 'portable', '30cm'], true, true, 'สวัสดีค่ะ สนใจบ้องอะคริลิกตกไม่แตก', ARRAY['Portable', 'Durable', 'Easy Clean'], '[{"label": "1 กล่อง", "price": 990}]', 30);
INSERT INTO products (id, name, slug, category, short_description, long_description, price_display, price_value, image, tags, featured, in_stock, line_inquiry_text, sort_order) VALUES
  ('grinder-premium', 'Premium Grinder', 'grinder-premium', 'accessory', '4-piece metal grinder — sharp teeth, kief catcher', 'High-quality 4-piece metal grinder with razor-sharp teeth and built-in kief catcher. Essential accessory for any connoisseur.', '฿250', 250, '/images/products/grinder.jpg', ARRAY['accessory', 'grinder', 'premium'], false, true, 'Hi! I''d like to buy the Premium Grinder.', 31);
